import { useState } from "react";

import {
  Container,
  Box,
  TextField,
  Button,
  Typography,
  Paper,
} from "@mui/material";

function App() {
  const [id, setId] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");

  const handleLogin = async () => {
    try {
      const response = await fetch("http://127.0.0.1:5000/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          id,
          password,
        }),
      });

      const data = await response.json();

      if (data.success) {
        setMessage("로그인 성공!");
      } else {
        setMessage(data.message);
      }
    } catch (error) {
      setMessage("서버 오류");
    }
  };

  return (
    <Container maxWidth="sm">
      <Box
        display="flex"
        justifyContent="center"
        alignItems="center"
        minHeight="100vh"
      >
        <Paper elevation={3} sx={{ padding: 4, width: "100%" }}>
          <Typography variant="h4" gutterBottom align="center">
            Login
          </Typography>

          <TextField
            fullWidth
            label="ID"
            margin="normal"
            value={id}
            onChange={(e) => setId(e.target.value)}
          />

          <TextField
            fullWidth
            type="password"
            label="Password"
            margin="normal"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <Button
            fullWidth
            variant="contained"
            sx={{ marginTop: 2 }}
            onClick={handleLogin}
          >
            로그인
          </Button>

          <Typography
            align="center"
            color="error"
            sx={{ marginTop: 2 }}
          >
            {message}
          </Typography>
        </Paper>
      </Box>
    </Container>
  );
}

export default App;
